import React from "react";
import "../styles/Clients.css";

export default function Clients() {
  return (
    <div className="clients">
      <div className="clients-heading">Our Clients</div>
      <div className="client-details">
        <div className="client">
          <div className="client-img"></div>
          <p className="client-name">SHREE SAI GAJANAN CHS LTD, DAVDI, DOMBIVLI EAST </p>
        </div>
        <div className="client">
          <div className="client-img"></div>
          <p className="client-name">For</p>
        </div>
        <div className="client">
          <div className="client-img"></div>
          <p className="client-name">Call</p>
        </div>
      </div>
    </div>
  );
}
